	private static List<String> immutableOrderedNames(List<String> names) {
		if (names == null || names.isEmpty()) {
			return List.of();
		}
		List<String> copy = new ArrayList<>(names.size());
		for (String name : names) {
			if (name != null && !name.isBlank()) {
				copy.add(name);
			}
		}
		return copy.isEmpty() ? List.of() : List.copyOf(copy);
	}

	private static Set<String> immutableNameSet(Set<String> names) {
		if (names == null || names.isEmpty()) {
			return Set.of();
		}
		for (String name : names) {
			if (name == null || name.isBlank()) {
				Set<String> copy = new LinkedHashSet<>();
				for (String candidate : names) {
					if (candidate != null && !candidate.isBlank()) {
						copy.add(candidate);
					}
				}
				return copy.isEmpty() ? Set.of() : Set.copyOf(copy);
			}
		}
		return Set.copyOf(names);
	}

